import * as React from 'react';
import type { Path } from '..';
import { Field, Form, useFieldContext } from '..';

export default {
  title: 'Components/ReactMiniForm/临时示例', // 注意：这里需要修改成自己对应 Component name。
  component: Form,
};

const inputKey = 'input/a' as const;
const selectKey = 'select.a' as const;
const checkboxKey = 'checkbox.a' as const;

interface InputValues {
  [inputKey]: string;
  [selectKey]?: string;
  [checkboxKey]: {
    b: boolean;
  };
}

const initialValues: InputValues = {
  [inputKey]: '123',
  [selectKey]: '123',
  [checkboxKey]: {
    b: true,
  },
};

const FieldError = ({ name }: { name: Path }) => (
  <div style={{ color: 'var(--R500)' }}>{useFieldContext({ name }).error}</div>
);

export const A = () => (
  <Form initialValues={initialValues} onSubmit={console.log}>
    <div>
      <Field name={inputKey} validate={v => (!v ? `'${inputKey}' should not be empty` : void 0)}>
        <input id="input" />
      </Field>
      <FieldError name={inputKey} />
    </div>
    <div>
      <Field name={[selectKey]} validate={v => (!v ? `'${selectKey}' should not be empty` : void 0)}>
        <select id="select">
          <option id="option-a">a</option>
          <option id="option-b">b</option>
        </select>
      </Field>
      <FieldError name={[selectKey]} />
    </div>
    <div>
      <Field name={[checkboxKey, 'b']} validate={v => (!v ? `'${checkboxKey}.b' should not be empty` : void 0)}>
        <input id="checkbox" type="checkbox" />
      </Field>
      <FieldError name={[checkboxKey, 'b']} />
    </div>
    <input id="submit" type="submit" />
  </Form>
);
